def compute_bmi(weight_kg, height_m):
    return weight_kg / (height_m ** 2)

def greet(name, greeting='Hello'):
    return f'{greeting}, {name}!'

# Test
people = [(70, 1.75), (60, 1.65), (90, 1.80)]
for w, h in people:
    print(f'BMI: {compute_bmi(w, h):.1f}')
print(greet('Alice'))
print(greet('Bob', 'Hi'))
```

